// src/core/digest.rs
// CHIMERA DIGEST ENGINE v1.0
// The sovereign synthesis layer that transforms Alpha Shards into executive intelligence

use anyhow::{Result, Context};
use serde::{Deserialize, Serialize};
use std::collections::HashMap;
use std::fs;
use std::path::{Path, PathBuf};
use chrono::{Utc, DateTime};
use crate::core::state::CompanyState;
use crate::mcp::McpBridge;
use colored::*;

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct AlphaShardDigest {
    pub timestamp: DateTime<Utc>,
    pub shard_id: String,
    pub symbol: String,

    // Reality Anchors
    pub physical_verification: PhysicalProof,
    pub reality_gap_percent: f64,

    // Smart Money Signals
    pub cot_signal: String,
    pub actionable_implication: String,

    // Integrity Metrics
    pub integrity_score: f64,
    pub manipulation_risk: String,
    pub financial_quality: String,
    pub missing_data_streams: Vec<String>,

    // Cosmic Context
    pub irritability_index: f64,
    pub macro_gravity: MacroGravity,

    // Sovereign Intelligence Correlation
    pub correlated_logs: Vec<LogCorrelation>,

    // Generated Directives
    pub strategic_posture: String,
    pub market_pulse: String,
    pub system_integrity: String,
    pub next_best_actions: Vec<DigestAction>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct PhysicalProof {
    pub facility: String,
    pub power_draw_mw: f64,
    pub satellite_confidence: f64,
    pub verification_timestamp: DateTime<Utc>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct MacroGravity {
    pub dxy: f64,
    pub yields_10yr: f64,
    pub vix: f64,
    pub fed_funds_probability: f64,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct LogCorrelation {
    pub log_source: String,
    pub correlation_strength: f64,
    pub key_insight: String,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct DigestAction {
    pub action_type: ActionType,
    pub tool_name: String,
    pub parameters: HashMap<String, String>,
    pub priority: u8, // 1-10, 10 = critical
    pub justification: String,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub enum ActionType {
    IntelligenceGapFill,
    MarketExecution,
    SystemMaintenance,
    TruthBroadcast,
    ProtocolEvolution,
}

pub struct ChimeraDigestEngine {
    log_dir: PathBuf,
    output_dir: PathBuf,
    intelligence_cache: HashMap<String, String>,
}

impl ChimeraDigestEngine {
    pub fn new() -> Result<Self> {
        let log_dir = PathBuf::from("logs");
        let output_dir = PathBuf::from("situation_room");

        // Ensure directories exist
        if !output_dir.exists() {
            fs::create_dir_all(&output_dir)?;
        }

        Ok(Self {
            log_dir,
            output_dir,
            intelligence_cache: HashMap::new(),
        })
    }

    /// Primary entry point: Process latest Alpha Shard and generate SITUATION_ROOM.md
    pub async fn process_shard(
        &mut self,
        shard_json: serde_json::Value,
        state: &CompanyState,
        mcp_bridge: Option<&mut McpBridge>
    ) -> Result<AlphaShardDigest> {
        println!("{}", "🔍 [DIGEST] Processing Alpha Shard...".bright_cyan().bold());

        // 1. Parse the raw shard
        let raw_shard = self.parse_shard_json(shard_json)?;

        // 2. Correlate with sovereign intelligence logs
        let log_correlations = self.correlate_with_logs(&raw_shard.symbol).await?;

        // 3. Assess integrity gaps
        let missing_streams = self.assess_integrity_gaps(&raw_shard);

        // 4. Generate strategic directives
        let strategic_posture = self.generate_strategic_posture(&raw_shard, &log_correlations);
        let market_pulse = self.generate_market_pulse(&raw_shard);
        let system_integrity = self.generate_system_integrity_report(&raw_shard, &missing_streams);
        let next_actions = self.generate_next_actions(&raw_shard, &missing_streams, state);

        // 5. Construct final digest
        let digest = AlphaShardDigest {
            timestamp: Utc::now(),
            shard_id: format!("SHARD_{}", Utc::now().timestamp()),
            symbol: raw_shard.symbol.clone(),
            physical_verification: raw_shard.physical_proof.unwrap_or_default(),
            reality_gap_percent: raw_shard.reality_gap.unwrap_or(0.0),
            cot_signal: raw_shard.cot_signal.unwrap_or_else(|| "UNKNOWN".to_string()),
            actionable_implication: raw_shard.actionable_implication.unwrap_or_else(|| "HOLD".to_string()),
            integrity_score: raw_shard.integrity_score.unwrap_or(0.0),
            manipulation_risk: raw_shard.manipulation_risk.unwrap_or_else(|| "UNKNOWN".to_string()),
            financial_quality: raw_shard.financial_quality.unwrap_or_else(|| "UNKNOWN".to_string()),
            missing_data_streams: missing_streams,
            irritability_index: raw_shard.irritability_index.unwrap_or(0.0),
            macro_gravity: raw_shard.macro_gravity.unwrap_or_default(),
            correlated_logs: log_correlations,
            strategic_posture,
            market_pulse,
            system_integrity,
            next_best_actions: next_actions,
        };

        // 6. Write situation room report
        self.write_situation_room(&digest).await?;

        // 7. Execute highest-priority action if MCP bridge available
        if let Some(bridge) = mcp_bridge {
            self.execute_top_action(&digest, bridge).await?;
        }

        Ok(digest)
    }

    fn parse_shard_json(&self, json: serde_json::Value) -> Result<RawAlphaShard> {
        // Implementation matches the structure from generate_alpha_shard
        // (Simplified for brevity - would match actual JSON structure)
        Ok(RawAlphaShard {
            symbol: json["symbol"].as_str().unwrap_or("UNKNOWN").to_string(),
            physical_proof: serde_json::from_value(json["physical_proof"].clone()).ok(),
            reality_gap: json["reality_gap"].as_f64(),
            cot_signal: json["cot_signal"].as_str().map(|s| s.to_string()),
            actionable_implication: json["actionable_implication"].as_str().map(|s| s.to_string()),
            integrity_score: json["integrity_score"].as_f64(),
            manipulation_risk: json["manipulation_risk"].as_str().map(|s| s.to_string()),
            financial_quality: json["financial_quality"].as_str().map(|s| s.to_string()),
            irritability_index: json["irritability_index"].as_f64(),
            macro_gravity: serde_json::from_value(json["macro_gravity"].clone()).ok(),
        })
    }

    async fn correlate_with_logs(&mut self, symbol: &str) -> Result<Vec<LogCorrelation>> {
        let mut correlations = Vec::new();

        // Read all intelligence logs
        let log_files = fs::read_dir(&self.log_dir)?;

        for entry in log_files {
            let path = entry?.path();
            if path.extension().and_then(|s| s.to_str()) == Some("txt") {
                let content = fs::read_to_string(&path)?;
                let log_name = path.file_stem().unwrap_or_default().to_string_lossy();

                // Simple keyword correlation
                let correlation = self.analyze_log_correlation(&content, symbol, &log_name);
                if correlation.correlation_strength > 0.3 {
                    correlations.push(correlation);
                }
            }
        }

        Ok(correlations)
    }

    fn analyze_log_correlation(&self, content: &str, symbol: &str, log_name: &str) -> LogCorrelation {
        let mut strength = 0.0;
        let mut insight = String::new();

        // Analyze based on log type
        match log_name {
            "adin_intel" => {
                if content.contains("Skills") && content.contains("procedural") {
                    strength = 0.8;
                    insight = "This shard exemplifies ADIN's 'Skills as leverage' principle".to_string();
                }
            }
            "sidhu_intel" => {
                if content.contains("satellite") || content.contains("thermal") {
                    strength = 0.9;
                    insight = "Physical thermal signature aligns with Sidhu's OSINT methodology".to_string();
                }
            }
            "roemmele_intel" => {
                if content.contains("Sovereignty") || content.contains("Ark") {
                    strength = 0.7;
                    insight = "This shard becomes part of our sovereign 'Ark' - private wisdom asset".to_string();
                }
            }
            _ => {
                // Generic correlation
                if content.contains(symbol) {
                    strength = 0.5;
                    insight = format!("Mention found in {} log", log_name);
                }
            }
        }

        LogCorrelation {
            log_source: log_name.to_string(),
            correlation_strength: strength,
            key_insight: insight,
        }
    }

    fn assess_integrity_gaps(&self, shard: &RawAlphaShard) -> Vec<String> {
        let mut missing = Vec::new();

        // Check for null data streams
        if shard.physical_proof.is_none() {
            missing.push("satellite_thermal".to_string());
        }
        if shard.cot_signal.is_none() {
            missing.push("cftc_cot".to_string());
        }
        if shard.macro_gravity.is_none() {
            missing.push("macro_indicators".to_string());
        }

        // Based on NVDA shard analysis
        if shard.integrity_score.unwrap_or(0.0) < 60.0 {
            missing.push("sec_filings".to_string());
            missing.push("news_sentiment".to_string());
            missing.push("supply_chain".to_string());
        }

        missing
    }

    fn generate_strategic_posture(&self, shard: &RawAlphaShard, logs: &[LogCorrelation]) -> String {
        let mut posture = String::new();

        // Physical reality check
        if let Some(physical) = &shard.physical_proof {
            posture.push_str(&format!(
                "Physical verification STRONG ({} MW draw at {}). ",
                physical.power_draw_mw, physical.facility
            ));
        }

        // Integrity assessment
        let integrity = shard.integrity_score.unwrap_or(0.0);
        posture.push_str(&format!(
            "Integrity score: {:.1}% ({}). ",
            integrity,
            if integrity > 70.0 { "HIGH" } else if integrity > 50.0 { "MODERATE" } else { "LOW" }
        ));

        // Cosmic context
        if let Some(irritability) = shard.irritability_index {
            if irritability > 1.5 {
                posture.push_str(&format!(
                    "Cosmic noise ELEVATED (Irritability: {:.2}). Expect deceptive signals. ",
                    irritability
                ));
            }
        }

        // Log correlations
        let top_log = logs.iter().max_by(|a, b| {
            a.correlation_strength.partial_cmp(&b.correlation_strength).unwrap()
        });

        if let Some(log) = top_log {
            posture.push_str(&format!(
                "Correlated with {} intelligence (strength: {:.1}).",
                log.log_source, log.correlation_strength
            ));
        }

        posture
    }

    fn generate_market_pulse(&self, shard: &RawAlphaShard) -> String {
        let mut pulse = String::new();

        if let Some(signal) = &shard.cot_signal {
            pulse.push_str(&format!("COT Signal: {}. ", signal));
        }

        if let Some(implication) = &shard.actionable_implication {
            pulse.push_str(&format!("Action: {}. ", implication));
        }

        let gap = shard.reality_gap.unwrap_or(0.0);
        pulse.push_str(&format!(
            "Reality Gap: {:.1}% ({})",
            gap,
            if gap.abs() < 5.0 { "Market pricing efficiently" } else { "Potential dislocation" }
        ));

        pulse
    }

    fn generate_system_integrity_report(&self, shard: &RawAlphaShard, missing: &[String]) -> String {
        let mut report = String::new();

        report.push_str(&format!(
            "Manipulation Risk: {}. Financial Quality: {}. ",
            shard.manipulation_risk.as_deref().unwrap_or("UNKNOWN"),
            shard.financial_quality.as_deref().unwrap_or("UNKNOWN")
        ));

        if !missing.is_empty() {
            report.push_str(&format!(
                "Missing data streams: {}. Priority: {}",
                missing.join(", "),
                if missing.contains(&"sec_filings".to_string()) { "HIGH" } else { "MEDIUM" }
            ));
        } else {
            report.push_str("All data streams active. System integrity HIGH.");
        }

        report
    }

    fn generate_next_actions(
        &self,
        shard: &RawAlphaShard,
        missing: &[String],
        state: &CompanyState
    ) -> Vec<DigestAction> {
        let mut actions = Vec::new();

        // 1. Fill intelligence gaps
        if missing.contains(&"sec_filings".to_string()) {
            actions.push(DigestAction {
                action_type: ActionType::IntelligenceGapFill,
                tool_name: "sec_poll_filings".to_string(),
                parameters: {
                    let mut map = HashMap::new();
                    map.insert("symbol".to_string(), shard.symbol.clone());
                    map
                },
                priority: 10,
                justification: "Boost forensic integrity score by analyzing SEC filings".to_string(),
            });
        }

        // 2. Broadcast truth if integrity sufficient
        if shard.integrity_score.unwrap_or(0.0) > 50.0 {
            actions.push(DigestAction {
                action_type: ActionType::TruthBroadcast,
                tool_name: "moltbook_broadcast".to_string(),
                parameters: {
                    let mut map = HashMap::new();
                    map.insert("submolt".to_string(), "truth".to_string());
                    map.insert("title".to_string(), format!("Alpha Shard: {} | Physical Verification", shard.symbol));
                    map.insert("content".to_string(), format!("Physical draw: {:.0}MW | Integrity: {:.1}% | Signal: {}", 
                        shard.physical_proof.as_ref().map(|p| p.power_draw_mw).unwrap_or(0.0),
                        shard.integrity_score.unwrap_or(0.0),
                        shard.cot_signal.as_deref().unwrap_or("NONE")));
                    map
                },
                priority: 7,
                justification: "Establish thought leadership with physically-verified alpha".to_string(),
            });
        }

        // 3. System self-audit
        actions.push(DigestAction {
            action_type: ActionType::SystemMaintenance,
            tool_name: "registry_audit".to_string(),
            parameters: {
                let mut map = HashMap::new();
                map.insert("agent_id".to_string(), "The_Cephalo_Don".to_string());
                map
            },
            priority: 8,
            justification: "Ensure our own integrity score remains high before external broadcast".to_string(),
        });

        // Sort by priority
        actions.sort_by(|a, b| b.priority.cmp(&a.priority));
        actions
    }

    async fn write_situation_room(&self, digest: &AlphaShardDigest) -> Result<()> {
        let timestamp = digest.timestamp.format("%Y%m%d_%H%M%S");
        let filename = format!("SITUATION_ROOM_{}_{}.md", digest.symbol, timestamp);
        let path = self.output_dir.join(filename);

        let markdown = self.generate_markdown_report(digest);

        fs::write(&path, markdown)?;
        println!("   [DIGEST] 🗺️ Situation Room written to: {}", path.display());

        Ok(())
    }

    fn generate_markdown_report(&self, digest: &AlphaShardDigest) -> String {
        format!(
            "# SITUATION ROOM: {} | {}\n\n\
            ## 🎯 STRATEGIC POSTURE\n\
            {}\n\n\
            ## 📊 MARKET PULSE\n\
            {}\n\n\
            ## 🛡️ SYSTEM INTEGRITY\n\
            {}\n\n\
            ## 🔗 INTELLIGENCE CORRELATIONS\n\
            {}\n\n\
            ## 🚀 NEXT BEST ACTIONS (Priority Order)\n\
            {}\n\n\
            ## 🧠 SOVEREIGN CONTEXT\n\
            Generated by Chimera Digest Engine v1.0 at {}\n\
            Shard Integrity: {:.1}% | Physical Verification: {} MW\n",
            digest.symbol,
            digest.timestamp.format("%Y-%m-%d %H:%M:%S UTC"),
            digest.strategic_posture,
            digest.market_pulse,
            digest.system_integrity,
            self.format_log_correlations(&digest.correlated_logs),
            self.format_actions(&digest.next_best_actions),
            digest.timestamp.format("%Y-%m-%d %H:%M:%S"),
            digest.integrity_score,
            digest.physical_verification.power_draw_mw
        )
    }

    fn format_log_correlations(&self, logs: &[LogCorrelation]) -> String {
        logs.iter()
            .map(|log| format!("- **{}**: {} (strength: {:.1})", log.log_source, log.key_insight, log.correlation_strength))
            .collect::<Vec<_>>()
            .join("\n")
    }

    fn format_actions(&self, actions: &[DigestAction]) -> String {
        actions.iter()
            .enumerate()
            .map(|(i, action)| {
                format!(
                    "{}. **{}** ({}) - {}\n   `{}` with params: {:?}\n",
                    i + 1,
                    action.tool_name,
                    match action.action_type {
                        ActionType::IntelligenceGapFill => "INTEL",
                        ActionType::MarketExecution => "TRADE",
                        ActionType::SystemMaintenance => "SYS",
                        ActionType::TruthBroadcast => "BROADCAST",
                        ActionType::ProtocolEvolution => "EVOLVE",
                    },
                    action.justification,
                    action.tool_name,
                    action.parameters
                )
            })
            .collect::<Vec<_>>()
            .join("\n")
    }

    async fn execute_top_action(&self, digest: &AlphaShardDigest, bridge: &mut McpBridge) -> Result<()> {
        if let Some(action) = digest.next_best_actions.first() {
            println!("   [DIGEST] ⚡ Executing top priority action: {}", action.tool_name);

            // Convert parameters to JSON
            let params = serde_json::json!(action.parameters);

            match bridge.call(&action.tool_name, Some(params)).await {
                Ok(result) => {
                    println!("   [DIGEST] ✅ Action executed: {}", result);

                    // Log execution
                    let log_path = self.output_dir.join("action_log.jsonl");
                    let log_entry = serde_json::json!({
                        "timestamp": Utc::now().to_rfc3339(),
                        "action": action.tool_name,
                        "digest_id": digest.shard_id,
                        "result": result
                    });

                    if let Ok(mut file) = fs::OpenOptions::new()
                        .create(true)
                        .append(true)
                        .open(log_path)
                    {
                        use std::io::Write;
                        let _ = writeln!(file, "{}", log_entry.to_string());
                    }
                }
                Err(e) => {
                    eprintln!("   [DIGEST] ❌ Action failed: {}", e);
                }
            }
        }

        Ok(())
    }
}

// Internal structures for parsing
#[derive(Debug)]
struct RawAlphaShard {
    symbol: String,
    physical_proof: Option<PhysicalProof>,
    reality_gap: Option<f64>,
    cot_signal: Option<String>,
    actionable_implication: Option<String>,
    integrity_score: Option<f64>,
    manipulation_risk: Option<String>,
    financial_quality: Option<String>,
    irritability_index: Option<f64>,
    macro_gravity: Option<MacroGravity>,
}

impl Default for PhysicalProof {
    fn default() -> Self {
        Self {
            facility: "UNKNOWN".to_string(),
            power_draw_mw: 0.0,
            satellite_confidence: 0.0,
            verification_timestamp: Utc::now(),
        }
    }
}

impl Default for MacroGravity {
    fn default() -> Self {
        Self {
            dxy: 104.2,
            yields_10yr: 4.2,
            vix: 15.0,
            fed_funds_probability: 0.0,
        }
    }
}
